import * as React from "react";
import Layout from "../components/layout";
import { StaticImage } from "gatsby-plugin-image";
import { graphql } from "gatsby";
import EducationComponent from "../components/EducationComponent";
import ExperienceComponent from "../components/ExperienceComponent";
import AwardComponent from "../components/AwardComponent";

const AboutMePage = ({ data }) => {
  console.log(data);
  return (
    <Layout>
      <section className="flex flex-row flex-wrap items-center justify-center bg-slate-300">
        <div className="md:w-1/5 p-5 w-full max-w-xs">
          <StaticImage
            className="rounded-full"
            src="../images/personal_photo.jpg"
            alt="Portrait photo of Douwe Hoekstra"
          />
        </div>
        <div className="w-4/5 p-5">
          <span className="text-3xl">
            Hi! I'm Douwe Hoekstra, a mathematician from the Netherlands,
            currently pursuing a Master's degree at the Radboud University
          </span>
        </div>
      </section>

      <section className="p-2">
      <h3 className="text-3xl font-semibold">Profile</h3>
        <p>
          <span className="font-semibold">
            Ever since I was twelve years old, I wanted to become a
            mathematician.
          </span>
          This, together with my broader interest in the natural sciences,
          formed my primary reason for studying both mathematics and physics. I
          obtained both BSc’s summa cum laude. Driven by my passion for
          mathematics, I am continuing my studies with a Master’s degree in
          mathematics. Simultaneously with this next step in my studies, I
          started broadening my horizon by taking on the positions of secretary
          and treasurer within several student organisations over the course of
          multiple years. This also led to my second passion for (Dutch) law.
          From a young age, I have been driven by curiosity, a strong sense of
          justice and my principles. I take responsibility, act independently or
          discuss/collaborate where necessary and get the job done! Helping
          others through what I do, and applying my talents and expertise, gives
          me satisfaction. My short-term goal is to obtain a PhD in mathematics.
          In the long term, I would like to be a mathematician in academia,
          contributing to the common body of knowledge.
        </p>
      </section>

      <section className="p-2">
        <h3 className="text-3xl font-semibold">Curriculum Vitae</h3>
        <h4 className="text-2xl pt-1 font-semibold">Education</h4>
        {data.cvYaml.education.map((e) => (
          <EducationComponent key={e.name} education={e} />
        ))}

        <h4 className="text-2xl pt-1 font-semibold">Employment History</h4>
        {data.cvYaml.employment.map((e) => (
          <ExperienceComponent experience={e} />
        ))}

        <h4 className="text-2xl pt-1 font-semibold">Miscellaneous Experience</h4>
        <h5 className="text-xl pt-1 font-semibold">Ancillary Activities</h5>
        {data.cvYaml.ancillary_activities.map(a => (
            <ExperienceComponent experience={a} />
        ))}

        <h5 className="text-xl pt-1 font-semibold">Awards and Achievements</h5>
        {data.cvYaml.awards.map(a => (
            <AwardComponent award={a} />
        ))}
      </section>
    </Layout>
  );
};

export const query = graphql`
  query {
    cvYaml {
      education {
        name
        institute
        from
        until
        description
        badges
      }
      employment {
        function
        institute
        from
        until
        description
      }
      ancillary_activities {
        function
        institute
        from
        until
        description
      }
      awards {
        name
        institute
        year
        description
      }
    }
  }
`;

export default AboutMePage;
